/// Before the Thunder swap this was a refcount bump: `SynapValue::Bytes` held
/// an `Arc<[u8]>`, so a SET moved the decoded argument into the store without
/// copying it. `thunder::Value::Bytes` owns a `Vec<u8>`, so the buffer is
/// copied once here instead — tracked upstream as the `Arc<[u8]>` payload
/// request on hivellm/thunder.
fn arg_shared(args: &[SynapValue], idx: usize) -> Result<Arc<[u8]>, String> {
    match args.get(idx) {
        Some(SynapValue::Bytes(b)) => Ok(b.as_slice().into()),
        // ...
    }
}
